def aggregate(daily_records, start_date, end_date):
    total_pdp = 0
    total_atc = 0
    total_chk = 0
    for rec in daily_records:
        d = datetime.strptime(rec["date"], "%Y-%m-%d")
        if start_date <= d <= end_date:
            total_pdp += rec["pdp_views"]
            total_atc += rec["atc"]
            total_chk += rec["checkouts"]
    return total_pdp, total_atc, total_chk


for csv_id, daily_data in all_daily.items():
    json_path = os.path.join(DIR, f"{csv_id}.json")
    if not os.path.exists(json_path):
        print(f"SKIP: {json_path} not found")
        continue
    with open(json_path, "r") as f:
        brand_data = json.load(f)
    perf = brand_data.get("performance", {})
    for period_name, (start, end) in periods.items():
        if period_name not in perf:
            continue
        pdp, atc, chk = aggregate(daily_data, start, end)
        perf[period_name]["pdp_views"] = pdp
        perf[period_name]["atc"] = atc
        perf[period_name]["checkouts"] = chk
    brand_data["performance"] = perf
    with open(json_path, "w") as f:
        json.dump(brand_data, f, indent=2)
    print(f"UPDATED: {csv_id} ({brand_data.get('brand_name', '?')})")

for csv_id in no_data:
    json_path = os.path.join(DIR, f"{csv_id}.json")
    if not os.path.exists(json_path):
        continue
    with open(json_path, "r") as f:
        brand_data = json.load(f)
    perf = brand_data.get("performance", {})
    for period_name in periods:
        if period_name in perf:
            perf[period_name]["pdp_views"] = 0
            perf[period_name]["atc"] = 0
            perf[period_name]["checkouts"] = 0
    brand_data["performance"] = perf
    with open(json_path, "w") as f:
        json.dump(brand_data, f, indent=2)
    print(f"UPDATED (no-data): {csv_id}")

print("\nDone.")
